+                input_prior,
+                super::LossMatrix::default(),
+                Vec::new(),
+            );
+
+            assert_eq!(
+                record.prior_compatible, 0.5,
+                "non-finite priors should normalize to neutral prior"
+            );
+            assert!(
+                record.metrics.posterior_compatible.is_finite(),
+                "posterior must remain finite for non-finite priors"
+            );
+        }
+    }
